import React from 'react';
import { NavLink } from 'react-router-dom';
import { useAuth } from '../contexts/AuthContext';
import {
  HomeIcon,
  ShoppingBagIcon,
  ArrowPathIcon,
  ChatBubbleLeftIcon,
  ChartBarIcon,
  UserGroupIcon,
  StarIcon,
  CogIcon,
  ClipboardDocumentListIcon
} from '@heroicons/react/24/outline';

const Sidebar = () => {
  const { isAdmin } = useAuth();

  const customerNavItems = [
    { name: 'Dashboard', path: '/customer/dashboard', icon: HomeIcon },
    { name: 'Transactions', path: '/customer/transactions', icon: ShoppingBagIcon },
    { name: 'Returns', path: '/customer/returns', icon: ArrowPathIcon },
    { name: 'Messages', path: '/customer/messages', icon: ChatBubbleLeftIcon },
    { name: 'Profile', path: '/customer/profile', icon: CogIcon },
  ];

  const adminNavItems = [
    { name: 'Dashboard', path: '/admin/dashboard', icon: HomeIcon },
    { name: 'Sensors', path: '/admin/sensors', icon: ChartBarIcon },
    { name: 'Transactions', path: '/admin/transactions', icon: ClipboardDocumentListIcon },
    { name: 'Returns', path: '/admin/returns', icon: ArrowPathIcon },
    { name: 'Ratings', path: '/admin/ratings', icon: StarIcon },
    { name: 'Messages', path: '/admin/messages', icon: ChatBubbleLeftIcon },
    { name: 'Reports', path: '/admin/reports', icon: ChartBarIcon },
    { name: 'Users', path: '/admin/users', icon: UserGroupIcon },
  ];

  const navItems = isAdmin ? adminNavItems : customerNavItems;

  return (
    <aside className="w-64 bg-white shadow-lg min-h-screen">
      <nav className="mt-5 px-2">
        {navItems.map((item) => (
          <NavLink
            key={item.path}
            to={item.path}
            className={({ isActive }) =>
              `group flex items-center px-2 py-2 text-sm font-medium rounded-md mb-1 ${
                isActive
                  ? 'bg-green-100 text-green-700'
                  : 'text-gray-600 hover:bg-gray-50 hover:text-gray-900'
              }`
            }
          >
            <item.icon
              className="mr-3 h-6 w-6"
              aria-hidden="true"
            />
            {item.name}
          </NavLink>
        ))}
      </nav>
    </aside>
  );
};

export default Sidebar;
